   118→      );
   119→      return acc;
   120→    },
   121→    {} as Record<string, propsItemsListCardTransition[]>,
   122→  );
   123→
   124→  const getSortedItemsByDate = (
   125→    items: propsItemsListCardTransition[],
   126→    date: string,
   127→  ) => {
   128→    return items.sort((a, b) => {
   129→      const transactionA = sortedTransactions.find(
   130→        t =>
   131→          getFormattedDateForHeader(t.date) === date &&
   132→          getTransactionCardItem(t).title === a.title,
   133→      );
   134→      const transactionB = sortedTransactions.find(
   135→        t =>
   136→          getFormattedDateForHeader(t.date) === date &&
   137→          getTransactionCardItem(t).title === b.title,
   138→      );
   139→
   140→      if (transactionA && transactionB) {
   141→        return moment(transactionB.date).diff(moment(transactionA.date));
   142→      }
   143→      return 0;
   144→    });
   145→  };
   146→
   147→  const getSortedByDate = (a: GroupedTransactions, b: GroupedTransactions) => {
   148→    const dateA = moment(a.date.split(' ').slice(1).join(' '), 'DD MMMM');
   149→    const dateB = moment(b.date.split(' ').slice(1).join(' '), 'DD MMMM');
